import 'dart:convert';
import 'package:http/http.dart' as http;


String url = 'https://api.example.com/api'; // URL to be used for HTTP.
String secureUrl = 'https://api.example.com/api'; // URL to be used for HTTPS.


Future<String> getExample(String url) async {
  try {
    var response = await http.get(url);

    if (response == null ||
        response.statusCode != 200) {
      throw 'Error occurred during HTTP request.';
    } else {
      return response.body;
    }

  } catch (e) {
    print('Error: $e');
  }
}


Future<String> getExampleSecure(String secureUrl) async {
  try {
